import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
export function mapScalarToTs(type: string): string {
  switch (type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      // Enum names and other types pass through unchanged.
      return type
  }
}

/**
 * The TypeScript type for a field as it appears in the model output interface.
 * Returns an empty string for relation (object) fields, which should be omitted.
 */
export function outputFieldType(field: DMMF.Field): string {
  if (field.kind === 'object') return ''
  const base = field.isList ? `${mapScalarToTs(field.type)}[]` : mapScalarToTs(field.type)
  return field.isRequired ? base : `${base} | null`
}

/**
 * The TypeScript type for a field in a write input context (CreateInput / UpdateInput).
 * Returns an empty string for relation (object) fields, which are excluded.
 */
export function writeInputFieldType(field: DMMF.Field): string {
  if (field.kind === 'object') return ''
  const base = field.isList ? `${mapScalarToTs(field.type)}[]` : mapScalarToTs(field.type)
  return field.isRequired ? base : `${base} | null`
}

/**
 * Whether a field should be marked as optional in a CreateInput type.
 * Auto-generated fields and fields with database-level defaults do not need
 * to be provided by the caller.
 */
export function isCreateInputOptional(field: DMMF.Field): boolean {
  return !field.isRequired || field.hasDefaultValue || !!field.isGenerated
}

