import type * as DMMF from '@prisma/dmmf'

import { isCreateInputOptional, mapScalarToTs, outputFieldType, writeInputFieldType } from './type-mapper'

function scalarFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object')
}

function identifierFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && (f.isId || f.isUnique))
}

function indented(lines: string[]): string {
  return lines.map((l) => `  ${l}`).join('\n')
}

/** Converts a PascalCase model name to a pluralised kebab-case REST resource path segment. */
function toResourcePath(modelName: string): string {
  return (
    modelName
      .replace(/([A-Z])/g, (char, _match, offset: number) => (offset === 0 ? char : `-${char}`))
      .toLowerCase() + 's'
  )
}

function generateModelInterface(model: DMMF.Model): string {
  const lines = scalarFields(model).map((f) => `${f.name}: ${outputFieldType(f)}`)
  return `export interface ${model.name} {\n${indented(lines)}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const lines = scalarFields(model).map((f) => {
    const opt = isCreateInputOptional(f) ? '?' : ''
    return `${f.name}${opt}: ${writeInputFieldType(f)}`
  })
  return `export interface ${model.name}CreateInput {\n${indented(lines)}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const lines = scalarFields(model).map((f) => `${f.name}?: ${writeInputFieldType(f)}`)
  return `export interface ${model.name}UpdateInput {\n${indented(lines)}\n}`
}

function generateWhereInput(model: DMMF.Model): string {
  const lines = scalarFields(model).map((f) => `${f.name}?: ${outputFieldType(f)}`)
  return `export interface ${model.name}WhereInput {\n${indented(lines)}\n}`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const lines = identifierFields(model).map((f) => {
    // Identifier fields are always non-null even when the column is nullable.
    const tsType = f.isList ? `${mapScalarToTs(f.type)}[]` : mapScalarToTs(f.type)
    return `${f.name}?: ${tsType}`
  })
  return `export interface ${model.name}WhereUniqueInput {\n${indented(lines)}\n}`
}

function generateOrderByInput(model: DMMF.Model): string {
  const lines = scalarFields(model).map((f) => `${f.name}?: 'asc' | 'desc'`)
  return `export interface ${model.name}OrderByInput {\n${indented(lines)}\n}`
}

function generateFindManyArgs(model: DMMF.Model): string {
  return [
    `export interface ${model.name}FindManyArgs {`,
    `  where?: ${model.name}WhereInput`,
    `  orderBy?: ${model.name}OrderByInput | ${model.name}OrderByInput[]`,
    `  take?: number`,
    `  skip?: number`,
    `}`,
  ].join('\n')
}

function generateModelClient(model: DMMF.Model): string {
  const m = model.name
  const resource = toResourcePath(m)
  return [
    `export class ${m}RestClient {`,
    `  #baseUrl: string`,
    `  #fetch: typeof globalThis.fetch`,
    ``,
    `  constructor(baseUrl: string, fetcher: typeof globalThis.fetch) {`,
    `    this.#baseUrl = baseUrl`,
    `    this.#fetch = fetcher`,
    `  }`,
    ``,
    `  async findMany(args?: ${m}FindManyArgs): Promise<${m}[]> {`,
    `    const query = new URLSearchParams()`,
    `    if (args?.where !== undefined) query.set('where', JSON.stringify(args.where))`,
    `    if (args?.orderBy !== undefined) query.set('orderBy', JSON.stringify(args.orderBy))`,
    `    if (args?.take !== undefined) query.set('take', String(args.take))`,
    `    if (args?.skip !== undefined) query.set('skip', String(args.skip))`,
    `    const qs = query.toString()`,
    `    const res = await this.#fetch(\`\${this.#baseUrl}/${resource}\${qs ? '?' + qs : ''}\`)`,
    `    if (!res.ok) throw new Error(\`GET /${resource} failed with status \${res.status}\`)`,
    `    return res.json() as Promise<${m}[]>`,
    `  }`,
    ``,
    `  async findUnique(where: ${m}WhereUniqueInput): Promise<${m} | null> {`,
    `    const query = new URLSearchParams({ where: JSON.stringify(where) })`,
    `    const res = await this.#fetch(\`\${this.#baseUrl}/${resource}/unique?\${query}\`)`,
    `    if (res.status === 404) return null`,
    `    if (!res.ok) throw new Error(\`GET /${resource}/unique failed with status \${res.status}\`)`,
    `    return res.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async create(data: ${m}CreateInput): Promise<${m}> {`,
    `    const res = await this.#fetch(\`\${this.#baseUrl}/${resource}\`, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify({ data }),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`POST /${resource} failed with status \${res.status}\`)`,
    `    return res.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async update(where: ${m}WhereUniqueInput, data: ${m}UpdateInput): Promise<${m}> {`,
    `    const res = await this.#fetch(\`\${this.#baseUrl}/${resource}\`, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify({ where, data }),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`PATCH /${resource} failed with status \${res.status}\`)`,
    `    return res.json() as Promise<${m}>`,
    `  }`,
    ``,
    `  async delete(where: ${m}WhereUniqueInput): Promise<${m}> {`,
    `    const res = await this.#fetch(\`\${this.#baseUrl}/${resource}\`, {`,
    `      method: 'DELETE',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify({ where }),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`DELETE /${resource} failed with status \${res.status}\`)`,
    `    return res.json() as Promise<${m}>`,
    `  }`,
    `}`,
  ].join('\n')
}

export type ModelCode = {
  modelName: string
  code: string
}

/**
 * Generates all TypeScript code for a single model: its output interface,
 * input types, and the REST client class.
