export function generateModelCode(model: DMMF.Model): ModelCode {
  const sections = [
    generateModelInterface(model),
    generateCreateInput(model),
    generateUpdateInput(model),
    generateWhereInput(model),
    generateWhereUniqueInput(model),
    generateOrderByInput(model),
    generateFindManyArgs(model),
    generateModelClient(model),
  ]
  return { modelName: model.name, code: sections.join('\n\n') }
}

