import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateModelCode } from './model-code-generator'

export type GenerateClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

function generateEnumDeclaration(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}`
}

function generateMainClient(modelNames: string[]): string {
  const propName = (name: string) => name.charAt(0).toLowerCase() + name.slice(1)
  const properties = modelNames.map((n) => `  readonly ${propName(n)}: ${n}RestClient`)
  const assignments = modelNames.map(
    (n) => `    this.${propName(n)} = new ${n}RestClient(options.baseUrl, fetcher)`,
  )
  return [
    `export type PrismaRestClientOptions = {`,
    `  /** Base URL of the REST API, e.g. "https://api.example.com/v1" */`,
    `  baseUrl: string`,
    `  /** Custom fetch implementation; defaults to globalThis.fetch */`,
    `  fetch?: typeof globalThis.fetch`,
    `}`,
    ``,
    `export class PrismaRestClient {`,
    ...properties,
    ``,
    `  constructor(options: PrismaRestClientOptions) {`,
    `    const fetcher = options.fetch ?? globalThis.fetch`,
    ...assignments,
    `  }`,
    `}`,
  ].join('\n')
}

/**
 * Generates the complete TypeScript source for a typed REST API client
 * derived from the given DMMF document. Returns the source as a string
 * so callers can test it without touching the filesystem.
 */
export function generateClientSource(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel

  const header = [
    `// This file was generated by @prisma/rest-api-client-generator`,
    `// Do not edit this file directly.`,
    `// prettier-ignore`,
    `/* eslint-disable */`,
  ].join('\n')

  const enumDeclarations = enums.map(generateEnumDeclaration)
  const modelSections = models.map(generateModelCode)
  const mainClient = generateMainClient(modelSections.map((s) => s.modelName))

  return [header, ...enumDeclarations, ...modelSections.map((s) => s.code), mainClient].join('\n\n') + '\n'
}

/** Generates the REST API client and writes it to `outputDir/index.ts`. */
export async function generateClient(options: GenerateClientOptions): Promise<void> {
  const source = generateClientSource(options.dmmf)
  await mkdir(options.outputDir, { recursive: true })
  await writeFile(path.join(options.outputDir, 'index.ts'), source, 'utf-8')
}

