import { generateClient } from './generate-client'

/** Prisma generator that emits a typed REST API client from a Prisma schema. */
export class RestApiClientGenerator implements Generator {
  readonly name = 'prisma-rest-api-client'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST API Client',
      defaultOutput: './generated/rest-client',
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error(
        `@prisma/rest-api-client-generator: output directory is required. ` +
          `Add 'output = "./generated/rest-client"' to the generator block in your Prisma config.`,
      )
    }

    await generateClient({ dmmf: options.dmmf, outputDir })
  }
}

