import { describe, expect, it } from 'vitest'

import { generateClientSource } from '../generate-client'
import { generateModelCode } from '../model-code-generator'
import { isCreateInputOptional, mapScalarToTs, outputFieldType } from '../type-mapper'
import type * as DMMF from '@prisma/dmmf'

// ---------------------------------------------------------------------------
// Test fixtures
// ---------------------------------------------------------------------------

function field(overrides: Partial<DMMF.Field> = {}): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    type: 'String',
    isRequired: true,
    isList: false,
    isId: false,
    isUnique: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function model(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as DMMF.Model
}

function dmmfDocument(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: { inputObjectTypes: {}, outputObjectTypes: { model: [], prisma: [] }, enumTypes: { prisma: [] }, fieldRefTypes: {} },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  } as unknown as DMMF.Document
}

const userModel = model('User', [
  field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
  field({ name: 'email', type: 'String', isUnique: true }),
  field({ name: 'name', type: 'String', isRequired: false }),
  field({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
  // relation field — must be excluded from all output
  field({ kind: 'object', name: 'posts', type: 'Post', isList: true, isRequired: false }),
])

// ---------------------------------------------------------------------------
// mapScalarToTs
// ---------------------------------------------------------------------------

describe('mapScalarToTs', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Uint8Array'],
  ])('maps %s -> %s', (prismaType, tsType) => {
    expect(mapScalarToTs(prismaType)).toBe(tsType)
  })

  it('passes through enum and model names unchanged', () => {
    expect(mapScalarToTs('Role')).toBe('Role')
    expect(mapScalarToTs('Category')).toBe('Category')
  })
})

// ---------------------------------------------------------------------------
// outputFieldType
// ---------------------------------------------------------------------------

describe('outputFieldType', () => {
  it('returns empty string for relation (object) fields', () => {
    expect(outputFieldType(field({ kind: 'object', type: 'Post' }))).toBe('')
  })

  it('returns plain type for required scalar', () => {
    expect(outputFieldType(field({ type: 'String', isRequired: true }))).toBe('string')
  })

  it('returns nullable type for optional scalar', () => {
    expect(outputFieldType(field({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  it('wraps list types in array notation', () => {
    expect(outputFieldType(field({ type: 'String', isList: true }))).toBe('string[]')
  })

  it('handles nullable list', () => {
    expect(outputFieldType(field({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })
})

// ---------------------------------------------------------------------------
// isCreateInputOptional
// ---------------------------------------------------------------------------

describe('isCreateInputOptional', () => {
  it('is false for required fields without defaults', () => {
    expect(isCreateInputOptional(field({ isRequired: true, hasDefaultValue: false }))).toBe(false)
  })

  it('is true for optional fields', () => {
    expect(isCreateInputOptional(field({ isRequired: false }))).toBe(true)
  })

  it('is true for required fields with a default value', () => {
    expect(isCreateInputOptional(field({ isRequired: true, hasDefaultValue: true }))).toBe(true)
  })

  it('is true for auto-generated fields', () => {
    expect(isCreateInputOptional(field({ isRequired: true, isGenerated: true }))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// generateModelCode — interface shape
// ---------------------------------------------------------------------------

describe('generateModelCode', () => {
  it('generates the model output interface with scalar fields only', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface User {')
    expect(code).toContain('id: number')
    expect(code).toContain('email: string')
    expect(code).toContain('name: string | null')
    expect(code).toContain('createdAt: Date')
    expect(code).not.toContain('posts')
  })

  it('generates CreateInput with optional id and createdAt', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserCreateInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email: string')
    expect(code).toContain('createdAt?: Date')
  })

  it('generates UpdateInput with all fields optional', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserUpdateInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email?: string')
    expect(code).toContain('name?: string | null')
  })

  it('generates WhereUniqueInput with id and unique fields', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserWhereUniqueInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email?: string')
    // non-unique, non-id fields must not appear
    expect(code.slice(code.indexOf('UserWhereUniqueInput'), code.indexOf('UserOrderByInput'))).not.toContain('name?')
  })

  it('generates OrderByInput with asc/desc for each scalar field', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain("export interface UserOrderByInput {")
    expect(code).toContain("id?: 'asc' | 'desc'")
    expect(code).toContain("email?: 'asc' | 'desc'")
  })

  it('generates FindManyArgs with pagination and filter fields', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserFindManyArgs {')
    expect(code).toContain('where?: UserWhereInput')
    expect(code).toContain('orderBy?: UserOrderByInput | UserOrderByInput[]')
    expect(code).toContain('take?: number')
    expect(code).toContain('skip?: number')
  })

  it('generates the REST client class with all CRUD methods', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export class UserRestClient {')
    expect(code).toContain('async findMany(args?: UserFindManyArgs): Promise<User[]>')
    expect(code).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(code).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(code).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(code).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  it('uses the pluralised kebab-case resource path in the REST client', () => {
    const { code } = generateModelCode(userModel)
    // resource path should be "users"
    expect(code).toContain('/users')
  })

  it('derives a kebab-case resource path for compound model names', () => {
    const compoundModel = model('UserProfile', [field({ name: 'id', type: 'Int', isId: true })])
    const { code } = generateModelCode(compoundModel)
    expect(code).toContain('/user-profiles')
  })
})

// ---------------------------------------------------------------------------
// generateClientSource — full document
// ---------------------------------------------------------------------------

describe('generateClientSource', () => {
  it('includes a generated-file header', () => {
    const source = generateClientSource(dmmfDocument([userModel]))
    expect(source).toContain('This file was generated by @prisma/rest-api-client-generator')
    expect(source).toContain('Do not edit this file directly.')
  })

  it('emits TypeScript union types for Prisma enums', () => {
    const roleEnum: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }
    const source = generateClientSource(dmmfDocument([userModel], [roleEnum]))
    expect(source).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits PrismaRestClient aggregating all model clients', () => {
    const source = generateClientSource(dmmfDocument([userModel]))
    expect(source).toContain('export class PrismaRestClient {')
    expect(source).toContain('readonly user: UserRestClient')
    expect(source).toContain('export type PrismaRestClientOptions')
    expect(source).toContain('baseUrl: string')
  })

  it('returns an empty-models document without model sections', () => {
    const source = generateClientSource(dmmfDocument([]))
    expect(source).toContain('This file was generated')
    expect(source).toContain('export class PrismaRestClient {')
    expect(source).not.toContain('RestClient {')
  })

  it('produces valid TypeScript that does not contain syntax errors (smoke test)', () => {
    const source = generateClientSource(dmmfDocument([userModel]))
    // Balanced braces are a minimal proxy for syntactic correctness.
    const opens = (source.match(/\{/g) ?? []).length
    const closes = (source.match(/\}/g) ?? []).length
    expect(opens).toBe(closes)
  })
})

