// isCreateInputOptional
// ---------------------------------------------------------------------------

describe('isCreateInputOptional', () => {
  it('is false for required fields without defaults', () => {
    expect(isCreateInputOptional(field({ isRequired: true, hasDefaultValue: false }))).toBe(false)
  })

  it('is true for optional fields', () => {
    expect(isCreateInputOptional(field({ isRequired: false }))).toBe(true)
  })

  it('is true for required fields with a default value', () => {
    expect(isCreateInputOptional(field({ isRequired: true, hasDefaultValue: true }))).toBe(true)
  })

  it('is true for auto-generated fields', () => {
    expect(isCreateInputOptional(field({ isRequired: true, isGenerated: true }))).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// generateModelCode — interface shape
// ---------------------------------------------------------------------------

describe('generateModelCode', () => {
  it('generates the model output interface with scalar fields only', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface User {')
    expect(code).toContain('id: number')
    expect(code).toContain('email: string')
    expect(code).toContain('name: string | null')
    expect(code).toContain('createdAt: Date')
    expect(code).not.toContain('posts')
  })

  it('generates CreateInput with optional id and createdAt', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserCreateInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email: string')
    expect(code).toContain('createdAt?: Date')
  })

  it('generates UpdateInput with all fields optional', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserUpdateInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email?: string')
    expect(code).toContain('name?: string | null')
  })

  it('generates WhereUniqueInput with id and unique fields', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserWhereUniqueInput {')
    expect(code).toContain('id?: number')
    expect(code).toContain('email?: string')
    // non-unique, non-id fields must not appear
    expect(code.slice(code.indexOf('UserWhereUniqueInput'), code.indexOf('UserOrderByInput'))).not.toContain('name?')
  })

  it('generates OrderByInput with asc/desc for each scalar field', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain("export interface UserOrderByInput {")
    expect(code).toContain("id?: 'asc' | 'desc'")
    expect(code).toContain("email?: 'asc' | 'desc'")
  })

  it('generates FindManyArgs with pagination and filter fields', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export interface UserFindManyArgs {')
    expect(code).toContain('where?: UserWhereInput')
    expect(code).toContain('orderBy?: UserOrderByInput | UserOrderByInput[]')
    expect(code).toContain('take?: number')
    expect(code).toContain('skip?: number')
  })

  it('generates the REST client class with all CRUD methods', () => {
    const { code } = generateModelCode(userModel)
    expect(code).toContain('export class UserRestClient {')
    expect(code).toContain('async findMany(args?: UserFindManyArgs): Promise<User[]>')
    expect(code).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(code).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(code).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(code).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  it('uses the pluralised kebab-case resource path in the REST client', () => {
    const { code } = generateModelCode(userModel)
    // resource path should be "users"
    expect(code).toContain('/users')
  })

  it('derives a kebab-case resource path for compound model names', () => {
    const compoundModel = model('UserProfile', [field({ name: 'id', type: 'Int', isId: true })])
    const { code } = generateModelCode(compoundModel)
    expect(code).toContain('/user-profiles')
  })
})

