    expect(source).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits PrismaRestClient aggregating all model clients', () => {
    const source = generateClientSource(dmmfDocument([userModel]))
    expect(source).toContain('export class PrismaRestClient {')
    expect(source).toContain('readonly user: UserRestClient')
    expect(source).toContain('export type PrismaRestClientOptions')
    expect(source).toContain('baseUrl: string')
  })

  it('returns an empty-models document without model sections', () => {
    const source = generateClientSource(dmmfDocument([]))
    expect(source).toContain('This file was generated')
    expect(source).toContain('export class PrismaRestClient {')
    expect(source).not.toContain('RestClient {')
  })

