export type Status = 'DRAFT' | 'PUBLISHED'

export interface Post {
  id: number
  title: string
  published: boolean
}

export interface PostCreateInput {
  id?: number
  title: string
  published?: boolean
}

export interface PostUpdateInput {
  id?: number
  title?: string
  published?: boolean
}

export interface PostWhereInput {
  id?: number
  title?: string
  published?: boolean
}

export interface PostWhereUniqueInput {
  id?: number
}

export interface PostOrderByInput {
  id?: 'asc' | 'desc'
  title?: 'asc' | 'desc'
  published?: 'asc' | 'desc'
}

export interface PostFindManyArgs {
  where?: PostWhereInput
  orderBy?: PostOrderByInput | PostOrderByInput[]
  take?: number
  skip?: number
}

export class PostRestClient {
  #baseUrl: string
  #fetch: typeof globalThis.fetch

  constructor(baseUrl: string, fetcher: typeof globalThis.fetch) {
    this.#baseUrl = baseUrl
    this.#fetch = fetcher
  }

  async findMany(args?: PostFindManyArgs): Promise<Post[]> {
    const query = new URLSearchParams()
    if (args?.where !== undefined) query.set('where', JSON.stringify(args.where))
    if (args?.orderBy !== undefined) query.set('orderBy', JSON.stringify(args.orderBy))
    if (args?.take !== undefined) query.set('take', String(args.take))
    if (args?.skip !== undefined) query.set('skip', String(args.skip))
    const qs = query.toString()
    const res = await this.#fetch(`${this.#baseUrl}/posts${qs ? '?' + qs : ''}`)
    if (!res.ok) throw new Error(`GET /posts failed with status ${res.status}`)
    return res.json() as Promise<Post[]>
  }

  async findUnique(where: PostWhereUniqueInput): Promise<Post | null> {
    const query = new URLSearchParams({ where: JSON.stringify(where) })
    const res = await this.#fetch(`${this.#baseUrl}/posts/unique?${query}`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(`GET /posts/unique failed with status ${res.status}`)
    return res.json() as Promise<Post>
  }

  async create(data: PostCreateInput): Promise<Post> {
    const res = await this.#fetch(`${this.#baseUrl}/posts`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ data }),
    })
    if (!res.ok) throw new Error(`POST /posts failed with status ${res.status}`)
    return res.json() as Promise<Post>
  }

  async update(where: PostWhereUniqueInput, data: PostUpdateInput): Promise<Post> {
    const res = await this.#fetch(`${this.#baseUrl}/posts`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ where, data }),
    })
    if (!res.ok) throw new Error(`PATCH /posts failed with status ${res.status}`)
    return res.json() as Promise<Post>
  }

  async delete(where: PostWhereUniqueInput): Promise<Post> {
    const res = await this.#fetch(`${this.#baseUrl}/posts`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ where }),
    })
    if (!res.ok) throw new Error(`DELETE /posts failed with status ${res.status}`)
    return res.json() as Promise<Post>
  }
}

export type PrismaRestClientOptions = {
  /** Base URL of the REST API, e.g. "https://api.example.com/v1" */
  baseUrl: string
  /** Custom fetch implementation; defaults to globalThis.fetch */
  fetch?: typeof globalThis.fetch
}

export class PrismaRestClient {
  readonly post: PostRestClient

  constructor(options: PrismaRestClientOptions) {
    const fetcher = options.fetch ?? globalThis.fetch
    this.post = new PostRestClient(options.baseUrl, fetcher)
  }
}
